    using namespace sqlgen;
    using namespace sqlgen::literals;

    auto result = sqlite::connect("test_db.sqlite")
        .and_then(drop_table<Product> | if_exists)
        .and_then(create_table<Product> | if_not_exists)
        .and_then(begin_transaction)
        .and_then([&products](auto conn) {
            for (const auto& product : products) {
                auto insert_result = insert(product).execute(conn);
                if (insert_result.is_error()) {
                    return insert_result;
                }
                conn = insert_result.value();
            }
            return result::ok(conn);
        })
        .and_then(commit_transaction);

    return result.is_ok();
}

}  // namespace batch_insert_products

