```cpp
#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    sqlgen::PrimaryKey<std::string> SNo;
    std::string SName;
    std::optional<int> Sex = 1;
    std::optional<std::string> Birthday;
    std::optional<int> Major;
    std::optional<float> Scorses = 0.0f;
    std::optional<std::string> Remark;
  };

  struct Course {
    sqlgen::PrimaryKey<int> CID;
    std::string CName;
    std::optional<int> Term = 1;
    std::optional<int> CTime;
    float Credit = 0.0f;
  };

  struct Score {
    std::string SNo;
    int CID;
    std::optional<float> Score;
  };

  void design_eas_database() {
    // Remove existing database file if it exists
    std::filesystem::remove("test_db.sqlite");

    // Connect to SQLite database
    sqlgen::Database<sqlgen::sqlite::Connection> db("test_db.sqlite");

    // Create Student table
    db.create_table<Student>(sqlgen::TableOptions{
        .table_name = "Student",
        .columns = {
            {"SNo", sqlgen::varchar(10), sqlgen::NotNull{}},
            {"SName", sqlgen::varchar(30), sqlgen::NotNull{}},
            {"Sex", sqlgen::Default{1}},
            {"Birthday", sqlgen::datetime},
            {"Major", sqlgen::integer},
            {"Scorses", sqlgen::real, sqlgen::Default{0.0f}},
            {"Remark", sqlgen::text}
        }
    });

    // Create Course table with auto-increment
    db.execute(R"(
        CREATE TABLE Course (
            CID INTEGER PRIMARY KEY AUTOINCREMENT,
            CName VARCHAR(30) NOT NULL,
            Term INTEGER DEFAULT 1,
            CTime INTEGER,
            Credit REAL NOT NULL DEFAULT 0
        )
    )");

    // Create Score table with composite primary key and foreign keys
    db.execute(R"(
        CREATE TABLE Score (
            SNo VARCHAR(10) NOT NULL,
            CID INTEGER NOT NULL,
            Score REAL,
            PRIMARY KEY (SNo, CID),
            FOREIGN KEY (SNo) REFERENCES Student(SNo),
            FOREIGN KEY (CID) REFERENCES Course(CID)
        )
    )");
  }

}
