```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <chrono>
#include <iomanip>
#include <sstream>

namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to SQLite database
    sqlgen::sqlite::Database db("test_db.sqlite");

    // Create User table
    db.execute(R"(
        CREATE TABLE IF NOT EXISTS User (
            user_id INTEGER PRIMARY KEY,
            username TEXT NOT NULL
        )
    )");

    // Create Post table
    db.execute(R"(
        CREATE TABLE IF NOT EXISTS Post (
            post_id INTEGER PRIMARY KEY,
            user_id INTEGER,
            created_at TEXT NOT NULL,
            FOREIGN KEY (user_id) REFERENCES User(user_id)
        )
    )");

    // Execute the query to find active users
    auto query = sqlgen::query<ActiveUser>()
        .distinct()
        .from<User>("u")
        .inner_join<Post>("p", sqlgen::on("u.user_id", "p.user_id"))
        .where(sqlgen::gte("p.created_at", sqlgen::date("2025-12-01")) 
               && sqlgen::lte("p.created_at", sqlgen::date("2025-12-31")));

    return db.execute(query);
}

}  // namespace query_active_users_posts
```

