#include <vector>

namespace query_daily_traffic_metrics {

struct PageVisit {
  sqlgen::PrimaryKey<int> visit_id;
  std::string url;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> visit_time;
};

struct DailyTraffic {
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

struct DailyTrafficView {
  static constexpr const char* tablename = "DailyTrafficView";
  static constexpr bool is_view = true;
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

/**
 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlite::Connection::open("test_db.sqlite").value();

  // Build the query using sqlgen's query builder
  auto query = select(
    strftime<"%Y-%m-%d">(column<PageVisit>(&PageVisit::visit_time)).as(&DailyTrafficView::visit_date),
    count<PageVisit>(asterisk<PageVisit>()).as(&DailyTrafficView::total_visits),
    count_distinct<PageVisit>(column<PageVisit>(&PageVisit::url)).as(&DailyTrafficView::unique_pages)
  ).from<PageVisit>().group_by(strftime<"%Y-%m-%d">(column<PageVisit>(&PageVisit::visit_time))).order_by(column<DailyTrafficView>(&DailyTrafficView::visit_date));

  // Execute the query and get results as DailyTrafficView objects
  auto view_results = query.execute(conn).value();

  // Convert DailyTrafficView to DailyTraffic
  std::vector<DailyTraffic> results;
  results.reserve(view_results.size());

  for (const auto& view : view_results) {
    results.push_back(DailyTraffic{
      .visit_date = view.visit_date,
      .total_visits = view.total_visits,
      .unique_pages = view.unique_pages
    });
  }

  return results;
}

}  // namespace query_daily_traffic_metrics
