            sqlgen::sum("s.amount"_c).as("total_amt")
        )
        .from<Product>().as("p")
        .join<Sale>().as("s").on("p.product_id"_c == "s.product_id"_c)
        .group_by("p.category"_c)
        .having(sqlgen::sum("s.amount"_c) > 5000)
    );

    // Execute the view creation
    conn | view_query;

    // Now query the view
    auto query = sqlgen::read<std::vector<ProductSalesReport>>;
    auto results = conn | query;

    // Convert to CategoryReport
    std::vector<CategoryReport> report;
    report.reserve(results.size());

    for (const auto& result : results) {
        report.push_back(CategoryReport{
            result.category,
            result.total_qty,
            result.total_amt
        });
    }

    return report;
}

}  // namespace query_product_sales_report
```

The second approach is more comprehensive and follows the pattern shown in the repository examples, where views are created and then queried. It properly uses the `sqlgen` library's fluent interface to build the SQL query with joins, grouping, and having clauses.

