```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Start with base SELECT query
    auto query = select<Book>();

    // Add WHERE clauses dynamically based on non-null parameters
    if (filters.title_keyword) {
        query = query.where("title"_c.like("%" + *filters.title_keyword + "%"));
    }

    if (filters.min_year) {
        query = query.where("year"_c >= *filters.min_year);
    }

    if (filters.genre) {
        query = query.where("genre"_c == *filters.genre);
    }

    if (filters.max_price) {
        query = query.where("price"_c <= *filters.max_price);
    }

    // Execute the query and return results
    return sqlite::connect("test_db.sqlite")
           .and_then(query)
           .and_then(read<std::vector<Book>>)
           .value_or(std::vector<Book>{});
}

}  // namespace query_search_books_by_criteria
```

