    BEGIN
        INSERT INTO AuditLog (table_name, record_id, action, timestamp)
        VALUES ('Product', OLD.product_id, 'UPDATE', CURRENT_TIMESTAMP);
    END;
  )";

  // Execute the raw SQL to create the trigger
  auto exec_result = conn.exec(trigger_sql);

  // Return true if execution was successful, false otherwise
  return exec_result.has_value();
