namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = std::move(*conn_result);

  // Start transaction
  auto tx_result = conn.transaction();
  if (!tx_result) {
    return false;
  }
  auto tx = std::move(*tx_result);

  try {
    // Check if sender has sufficient funds
    auto sender_account = tx.read<Account>("account_id"_c == from_account_id);
    if (sender_account.empty() || sender_account[0].balance < amount) {
      tx.rollback();
      return false;
    }

    // Update sender's balance (deduct amount)
    auto update_sender = update<Account>()
      .set("balance"_c = "balance"_c - amount)
      .where("account_id"_c == from_account_id);

    auto sender_result = tx.execute(update_sender);
    if (!sender_result || sender_result->affected_rows() != 1) {
      tx.rollback();
      return false;
    }

    // Update receiver's balance (add amount)
    auto update_receiver = update<Account>()
      .set("balance"_c = "balance"_c + amount)
      .where("account_id"_c == to_account_id);

    auto receiver_result = tx.execute(update_receiver);
    if (!receiver_result || receiver_result->affected_rows() != 1) {
      tx.rollback();
      return false;
    }

    // Commit transaction
    auto commit_result = tx.commit();
    return commit_result.has_value();

  } catch (const std::exception&) {
    // Rollback if any exception occurs
    tx.rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
