Here's the complete implementation of the `update_order_status` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
   // Connect to the SQLite database
   auto conn = sqlgen::sqlite::connection::open("test_db.sqlite");

   int total_affected_rows = 0;

   // Update 'pending' orders older than 7 days to 'expired'
   auto update_expired = sqlgen::update<Order>(conn)
        .set(&Order::status, "expired")
        .where(sqlgen::eq(&Order::status, "pending") && 
               sqlgen::lt(&Order::order_date, sqlgen::sqlite::date("now", "-7 days")));

   total_affected_rows += update_expired.execute();

   // Update 'shipped' orders to 'delivered' (simulating delivery confirmation)
   auto update_delivered = sqlgen::update<Order>(conn)
        .set(&Order::status, "delivered")
        .where(sqlgen::eq(&Order::status, "shipped"));

   total_affected_rows += update_delivered.execute();

   return total_affected_rows;
}

} // namespace update_order_status
```

This implementation:

1. **Connects to the database** using `sqlgen::sqlite::connection::open("test_db.sqlite")`

2. **Updates pending orders older than 7 days to expired** using:
   - `sqlgen::update<Order>(conn)` to create an update statement
   - `.set(&Order::status, "expired")` to set the new status
   - `.where()` with conditions: status equals "pending" AND order_date is less than 7 days ago using SQLite's date function

3. **Updates shipped orders to delivered** using similar syntax but with a simpler condition

4. **Returns the total number of affected rows** by summing the results from both update operations

The code uses `sqlgen`'s type-safe query builder syntax with member pointers (`&Order::status`, `&Order::order_date`) and SQLite-specific date functions (`sqlgen::sqlite::date("now", "-7 days")`) to handle the date comparison properly.

