```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Create in-memory database connection
  auto connection = Connection::in_memory();

  // Create the Event table
  auto create_table = CreateTable<Event>{};
  connection.execute(to_sql(create_table));

  // Insert events into the table
  for (const auto& event : events) {
    auto insert = Insert<Event>{event};
    connection.execute(to_sql(insert));
  }

  // Execute the temporal analysis query
  std::vector<TemporalAnalysis> results;

  // Custom query with SQLite date/time functions
  std::string query = R"(
    SELECT 
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) as start_day,
      CAST(strftime('%m', start_time) AS INTEGER) as start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
      CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) as start_second,
      CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
      CAST(strftime('%s', start_time) AS INTEGER) as start_epoch,
      CASE 
        WHEN end_time IS NOT NULL THEN 
          (julianday(end_time) - julianday(start_time))
        ELSE NULL
      END as duration_days
    FROM Event
    WHERE end_time IS NOT NULL;
  )";

  // Execute query and process results
  connection.execute(query, [&results](const auto& row) {
    TemporalAnalysis analysis;
    analysis.event_id = std::get<0>(row);
    analysis.event_name = std::get<1>(row);
    analysis.start_day = std::get<2>(row);
    analysis.start_month = std::get<3>(row);
    analysis.start_year = std::get<4>(row);
    analysis.start_hour = std::get<5>(row);
    analysis.start_minute = std::get<6>(row);
    analysis.start_second = std::get<7>(row);
    analysis.start_weekday = std::get<8>(row);
    analysis.start_epoch = std::get<9>(row);

    // Handle optional duration_days
    auto duration = std::get<10>(row);
    if (!duration.is_null()) {
      analysis.duration_days = duration.as_double();
    }

    results.push_back(std::move(analysis));
  });

  return results;
}

}  // namespace analyze_temporal_data
```

This implementation:

1. **Connects to SQLite**: Uses an in-memory SQLite database connection
2. **Creates the Event table**: Uses `sqlgen::CreateTable` to generate the table schema
3. **Inserts events**: Uses `sqlgen::Insert` to insert all provided events
4. **Performs temporal analysis**: Uses SQLite's date/time functions (`strftime`, `julianday`) to extract components and calculate durations
5. **Handles optional values**: Properly handles the optional `end_time` field and `duration_days` calculation
6. **Returns comprehensive results**: Maps the SQL results to the `TemporalAnalysis` struct

The SQL query uses SQLite-specific functions since the reference SQL functions (DAY, MONTH, YEAR, etc.) are MySQL/PostgreSQL specific. SQLite uses `strftime` with format specifiers for date component extraction and `julianday` for date difference calculations.

