bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;

  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Inventory>(conn);
  create_table<Inventory>(conn);
  insert_or_replace(items)(conn);
  const auto rows =
      sqlgen::read<std::vector<Inventory>>(conn).value_or(std::vector<Inventory>{});
  return rows.size() >= items.size();
}

