```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <unordered_map>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  // Perform upsert operation using insert_or_replace
  auto write_result = conn_result
                      .and_then(write<insert_or_replace>(items))
                      .map_error([](auto error) {
                        // Handle write error
                        return false;
                      });

  if (!write_result) {
    return false;
  }

  // Read back items to verify upsert behavior
  auto read_result = write_result
                     .and_then(read<std::vector<Inventory>>)
                     .map_error([](auto error) {
                       // Handle read error
                       return false;
                     });

  if (!read_result) {
    return false;
  }

  const auto& read_items = read_result.value();

  // Verify that all items were properly upserted
  // Create a map of item_id to quantity for verification
  std::unordered_map<int, std::pair<std::string, int>> expected_items;
  for (const auto& item : items) {
    expected_items[item.item_id.value] = {item.name, item.quantity};
  }

  // Check that all expected items exist in the database with correct values
  for (const auto& item : read_items) {
    auto it = expected_items.find(item.item_id.value);
    if (it != expected_items.end()) {
      // Verify name and quantity match
      if (item.name != it->second.first || item.quantity != it->second.second) {
        return false; // Data mismatch
      }
      expected_items.erase(it);
    }
  }

  // All expected items should have been found and removed from the map
  return expected_items.empty();
}

}  // namespace upsert_inventory_items
