    auto friend_count_query = R"(
      SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      ORDER BY friend_count DESC
    )"_sql;

    auto friend_counts = db.execute(friend_count_query);
    std::cout << "\nFriend Counts per User:" << std::endl;
    for (const auto& row : friend_counts) {
      std::cout << row.get<std::string>(1) << ": " << row.get<int>(2) 
                << " friends" << std::endl;
    }

    // 5. Find users in the same city who are not yet friends (recommendation)
    auto same_city_recommendation_query = R"(
      SELECT u1.username, u2.username, u1.city
      FROM User u1
      JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
      WHERE u1.city IS NOT NULL 
        AND NOT EXISTS (
          SELECT 1 FROM Friendship f 
          WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
             OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
        )
    )"_sql;

    auto same_city_recommendations = db.execute(same_city_recommendation_query);
    std::cout << "\nSame City Friend Recommendations:" << std::endl;
    for (const auto& row : same_city_recommendations) {
      std::cout << row.get<std::string>(0) << " and " << row.get<std::string>(1)
                << " (both in " << row.get<std::string>(2) << ")" << std::endl;
    }

  } catch (const std::exception& e) {
    std::cerr << "Database error: " << e.what() << std::endl;
  }

  return results;
}

}  // namespace analyze_social_network

