```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  const auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Create temporary table for OrderItem data
  sqlgen::write(conn, items).value();

  // Execute the comprehensive order metrics query
  const auto metrics = sqlgen::read<std::vector<OrderMetrics>>(conn, 
      "SELECT "
      "  item_id, "
      "  order_id, "
      "  product_id, "
      "  unit_price, "
      "  quantity, "
      "  COALESCE(discount_rate, 0) as discount_rate, "
      "  COALESCE(tax_rate, 0) as tax_rate, "
      "  (unit_price * quantity) as gross_total, "
      "  (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100)) as discounted_total, "
      "  (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100) * (1 + COALESCE(tax_rate, 0)/100)) as final_total, "
      "  (unit_price * quantity / quantity) as unit_cost, "
      "  (quantity % 10) as quantity_group, "
      "  (unit_price * 0.3) as estimated_profit "
      "FROM OrderItem").value();

  return metrics;
}

}  // namespace calculate_order_metrics
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlgen::sqlite::connect()`
2. **Writes the input items** to the database using `sqlgen::write()`
3. **Executes the comprehensive SQL query** that performs all the required arithmetic operations:
   - **Multiplication**: `unit_price * quantity` for gross total
   - **Division**: `discount_rate/100` and `tax_rate/100` for percentage calculations
   - **Addition/Subtraction**: `1 - discount_rate/100` and `1 + tax_rate/100` for discount and tax application
   - **Modulo**: `quantity % 10` for quantity grouping
   - **Business metrics**: Profit estimation with `unit_price * 0.3`
4. **Handles NULL values** using `COALESCE` to provide default values of 0 for optional discount and tax rates
5. **Returns the results** as a vector of `OrderMetrics` structures containing all calculated values

The code follows the patterns shown in the provided code fragments, particularly the SQLite connection handling and table operations demonstrated in the test files.

