 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  // Connect to the SQLite database
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Build the join query using sqlgen's fluent interface
  auto query = sqlgen::sqlite::select(
      sqlgen::column<Order>(&Order::order_id).as(&Consolidated::order_id),
      sqlgen::column<Customer>(&Customer::name).as(&Consolidated::customer_name),
      sqlgen::column<Payment>(&Payment::amount).as(&Consolidated::amount)
    )
    .from<Order>()
    .inner_join<Customer>(sqlgen::on<Order, Customer>(&Order::customer_id, &Customer::customer_id))
    .inner_join<Payment>(sqlgen::on<Order, Payment>(&Order::order_id, &Payment::order_id))
    .order_by(sqlgen::column<Payment>(&Payment::amount), sqlgen::DESC);

