```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <cassert>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Enable foreign key support (required for SQLite)
  conn.execute("PRAGMA foreign_keys = ON");

  // Drop tables if they exist to start fresh
  conn.execute("DROP TABLE IF EXISTS Child");
  conn.execute("DROP TABLE IF EXISTS Parent");

  // Create Parent table
  conn.execute(R"(
    CREATE TABLE Parent (
      parent_id INTEGER PRIMARY KEY,
      name TEXT NOT NULL
    )
  )");

  // Create Child table with CASCADE DELETE foreign key constraint
  conn.execute(R"(
    CREATE TABLE Child (
      child_id INTEGER PRIMARY KEY,
      parent_id INTEGER,
      note TEXT,
      FOREIGN KEY (parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE
    )
  )");

  // Insert parent record
  Parent parent1{.parent_id = 1, .name = "Test Parent"};
  conn.insert(parent1);

  // Insert child records with the same parent_id
  std::vector<Child> children = {
    Child{.child_id = 1, .parent_id = 1, .note = "First child"},
    Child{.child_id = 2, .parent_id = 1, .note = "Second child"},
    Child{.child_id = 3, .parent_id = 1, .note = "Third child"}
  };

  for (const auto& child : children) {
    conn.insert(child);
  }

  // Verify children exist before deletion
  auto children_before = conn.select<Child>().where(Child::parent_id == 1).all();
  assert(children_before.size() == 3 && "Should have 3 children before deletion");

  // Delete the parent (this should cascade to children)
  conn.delete_<Parent>().where(Parent::parent_id == 1).execute();

  // Verify children are automatically deleted
  auto children_after = conn.select<Child>().where(Child::parent_id == 1).all();

  // Clean up
  conn.execute("DROP TABLE IF EXISTS Child");
  conn.execute("DROP TABLE IF EXISTS Parent");

  // Return verification result
  return children_after.empty();
}

}  // namespace cascade_delete_demo
