  using namespace sqlgen::literals;

  try {
    // Connect to SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn) {
      return false;
    }

    // 1. Create Account table
    auto create_result = conn->and_then(create_table<Account> | if_not_exists);
    if (!create_result) {
      return false;
    }

    // Insert some test data
    std::vector<Account> initial_accounts = {
        Account{.account_id = 1, .balance = 1000.0, .status = "active"},
        Account{.account_id = 2, .balance = 500.0, .status = "inactive"},
        Account{.account_id = 3, .balance = 2500.0, .status = "active"}
    };

    auto insert_result = create_result->and_then(insert(initial_accounts));
    if (!insert_result) {
      return false;
    }

    // 2. Update balances and statuses using set(...)

    // Update account 1: increase balance by 10% and change status
    auto update1_result = insert_result->and_then(
        update<Account>(set("balance"_c = "balance"_c * 1.1, 
                           "status"_c = "premium"),
                       where("account_id"_c == 1))
    );
    if (!update1_result) {
      return false;
    }

    // Update account 2: set specific values and activate
    auto update2_result = update1_result->and_then(
        update<Account>(set("balance"_c = 750.0, 
                           "status"_c = "active"),
                       where("account_id"_c == 2))
    );
    if (!update2_result) {
      return false;
    }

    // Update account 3: decrease balance and set status
    auto update3_result = update2_result->and_then(
        update<Account>(set("balance"_c = "balance"_c - 500.0, 
                           "status"_c = "review"),
                       where("account_id"_c == 3))
    );
    if (!update3_result) {
      return false;
    }

    // 3. Verify changes persisted
    auto read_result = update3_result->and_then(read<std::vector<Account>>);
    if (!read_result) {
      return false;
    }

    const auto& updated_accounts = read_result.value();

    // Verify the updates
    bool all_updates_correct = true;

    for (const auto& account : updated_accounts) {
      if (account.account_id == 1) {
        all_updates_correct = all_updates_correct && 
                             (account.balance == 1100.0) && 
                             (account.status == "premium");
      } else if (account.account_id == 2) {
        all_updates_correct = all_updates_correct && 
                             (account.balance == 750.0) && 
                             (account.status == "active");
      } else if (account.account_id == 3) {
        all_updates_correct = all_updates_correct && 
                             (account.balance == 2000.0) && 
                             (account.status == "review");
      }
    }

    return all_updates_correct;

  } catch (...) {
    return false;
  }
}

}  // namespace update_set_operations

