#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Since SQLite doesn't support FULL JOIN natively, we simulate it with LEFT JOIN and UNION
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
                .and_then([](auto conn) {
                  // First part: Suppliers with their products (LEFT JOIN)
                  auto left_join = conn.template query<SupProd>(
                    "SELECT s.name as supplier_name, p.name as product_name "
                    "FROM Supplier s "
                    "LEFT JOIN Product p ON s.supplier_id = p.supplier_id"
                  );

                  // Second part: Products without suppliers (using LEFT JOIN in reverse)
                  auto right_join = conn.template query<SupProd>(
                    "SELECT s.name as supplier_name, p.name as product_name "
                    "FROM Product p "
                    "LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id "
                    "WHERE s.supplier_id IS NULL"
                  );

                  // Combine both results
                  if (left_join && right_join) {
                    auto combined = left_join.value();
                    auto right_results = right_join.value();
                    combined.insert(combined.end(), right_results.begin(), right_results.end());
                    return combined;
                  }

                  // Return empty vector if there was an error
                  return std::vector<SupProd>{};
                });

  return result.value_or(std::vector<SupProd>{});
}

}  // namespace full_join_suppliers_products

