Here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace order_by_descending {

struct Score {
  sqlgen::PrimaryKey<int> id;
  int points;
};

/**
 * This function demonstrates ORDER BY DESC.
 * Returns: std::string.
 */
inline std::string order_by_descending() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Construct a query to select scores ordered by points in descending order
    auto query = sqlite::select<Score>().order_by(desc(&Score::points));

    // Return the generated SQL string
    return to_sql(query);
}

}  // namespace order_by_descending
```

