struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  double unit_price;
  int quantity;
};

struct OrderSummary {
  static constexpr const char* tablename = "OrderSummaryView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
  double total;
};

/**
 * Description: This function demonstrates creating a view.
 * Returns: std::vector<OrderSummary>.
 */
std::vector<OrderSummary> create_view_order_summary() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to SQLite database
    sqlite::Database db("test_db.sqlite");

    // Create the view using CREATE VIEW AS
    db.create_view_as<OrderSummary>(
        select(columns(&Order::order_id, &Order::customer, 
                      expr("SUM({}.unit_price * {}.quantity)", alias<OrderItem>(), alias<OrderItem>()).as("total")))
        .from<Order>()
        .join<OrderItem>(on(&Order::order_id, &OrderItem::order_id))
        .group_by(&Order::order_id, &Order::customer)
    );

    // Read from the view to verify data
    auto results = db.select_from<OrderSummary>();

    return results;
}

