```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto db = sqlite::connect("test_db.sqlite");

  // Define tables
  auto user_table = Table<User>("User");
  auto post_table = Table<Post>("Post");

  // Build the query with GROUP BY and aggregations
  auto query = select(
      user_table.user_id,
      user_table.name,
      count(post_table.post_id).as("post_count"),
      avg(length(post_table.content)).as("avg_length")
    )
    .from(user_table)
    .left_join(post_table).on(user_table.user_id == post_table.user_id)
    .group_by(user_table.user_id, user_table.name);

  // Execute the query and return results
  return db.execute(query);
}

}  // namespace group_by_with_aggregations
```

