Looking at the code fragments and the sqlgen library usage patterns, here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create a SELECT query that filters records where value > 100
    auto select_query = select("value"_c)(from<Source>(), where(gt("value"_c, 100)));

    // Create the CREATE TABLE AS SELECT statement
    return create_table_as<Target>(select_query);
}

}  // namespace create_table_as_select
```

This implementation:

1. Uses the `sqlgen` namespace and its literals for convenient column name syntax (`"value"_c`)
2. Creates a SELECT query that selects the `value` column from the `Source` table where `value > 100`
3. Uses `create_table_as<Target>` to create a CREATE TABLE AS SELECT statement that creates the `Target` table from the filtered results
4. Returns the constructed query value as required

The query will generate SQL similar to:
```sql
CREATE TABLE Target AS SELECT value FROM Source WHERE value > 100
```

